	resourceGroup               = "agentcube.volcano.sh"
	sessionResourceName         = "sessions"
	agentRuntimeResourceName    = "agentruntimes"
	codeInterpreterResourceName = "codeinterpreters"
)

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("resource has no pod template")
	ErrPublicKeyMissing        = errors.New("public key not yet loaded from Router Secret")
)

func NewSessionNotFoundError(sessionID string) error {
	return &sessionNotFoundError{
		sessionID: sessionID,
		groupResource: schema.GroupResource{
			Group:    resourceGroup,
			Resource: sessionResourceName,
		},
		Name: sessionID,
	}
}

type sessionNotFoundError struct {
	sessionID    string
	groupResource schema.GroupResource
}

func (e *sessionNotFoundError) Error() string {
	return fmt.Sprintf("session %s not found", e.sessionID)
}

func (e *sessionNotFoundError) GroupResource() schema.GroupResource {
	return e.groupResource
}

func (e *sessionNotFoundError) RouteCause() error {
	return nil
}

func (e *sessionNotFoundError) Cause() error {
	return nil
}

func (e *sessionNotFoundError) Details() []interface{} {
	return []interface{}{"name", e.Name}
}

func (e *sessionNotFoundError) Status() interface{} {
	return nil
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) error {
	var gr schema.GroupResource
	switch kind {
	case AgentRuntimeKind:
		gr = schema.GroupResource{Group: resourceGroup, Resource: agentRuntimeResourceName}
	case CodeInterpreterKind:
		gr = schema.GroupResource{Group: resourceGroup, Resource: codeInterpreterResourceName}
	default:
		gr = schema.GroupResource{Group: resourceGroup, Resource: agentRuntimeResourceName}
	}
	return &templateNotFoundError{
		namespace: namespace,
		name:      name,
		kind:      kind,
		groupResource: gr,
	}
}

type templateNotFoundError struct {
	namespace string
	name     string
	kind     string
	groupResource schema.GroupResource
}

func (e *templateNotFoundError) Error() string {
	return fmt.Sprintf("%s %s/%s not found", e.kind, e.namespace, e.name)
}

func (e *templateNotFoundError) GroupResource() schema.GroupResource {
	return e.groupResource
}

func (e *templateNotFoundError) RouteCause() error {
	return nil
}

func (e *templateNotFoundError) Cause() error {
	return nil
}

func (e *templateNotFoundError) Details() []interface{} {
	return []interface{}{"name", e.name}
}

func (e *templateNotFoundError) Status() interface{} {
	return nil
}

func NewUpstreamUnavailableError(err error) error {
	return fmt.Errorf("upstream unavailable: %w", err)
}

func NewInternalError(err error) error {
	if err == nil {
		return errors.New("internal server error")
	}
	return fmt.Errorf("internal server error: %w", err)
}

