package store

import "errors"

var ErrNotFound = errors.New("store: not found")

var ErrKeyNotExists = errors.New("key not exists")

package store

import (
	"os"
	"strings"
	"sync"

	"github.com/redis/go-redis/v9"
	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"
)

const (
	redisStoreType  string = "redis"
	valkeyStoreType string = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			klog.Fatalf("init store failed: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = redisStoreType
	}

	switch storeType {
	case redisStoreType:
		return initRedisStore()
	case valkeyStoreType:
		return initValkeyStore()
	default:
		return os.ErrInvalid
	}
}

func initRedisStore() error {
	redisAddr := os.Getenv("REDIS_ADDR")
	if redisAddr == "" {
		return os.ErrNotExist
	}

	redisPassword := os.Getenv("REDIS_PASSWORD")
	passwordRequired := strings.ToLower(os.Getenv("REDIS_PASSWORD_REQUIRED"))
	if redisPassword == "" && passwordRequired != "false" {
		return os.ErrPermission
	}

	cli := redis.NewClient(&redis.Options{
		Addr:     redisAddr,
		Password: redisPassword,
	})

	provider = &redisStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
	return nil
}

func initValkeyStore() error {
	valkeyAddr := os.Getenv("VALKEY_ADDR")
	if valkeyAddr == "" {
		return os.ErrNotExist
	}

	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED"))
	if valkeyPassword == "" && passwordRequired != "false" {
		return os.ErrPermission
	}

	opts := &valkey.ClientOption{
		InitAddress: strings.Split(valkeyAddr, ","),
		Password:    valkeyPassword,
	}

	if strings.ToLower(os.Getenv("VALKEY_DISABLE_CACHE")) == "true" {
		opts.DisableCache = true
	}
	if strings.ToLower(os.Getenv("VALKEY_FORCE_SINGLE")) == "true" {
		opts.ForceSingleClient = true
	}

	cli, err := valkey.NewClient(opts)
	if err != nil {
		return err
	}

	provider = &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
	return nil
}

func makeRedisOptions() *redis.Options {
	return &redis.Options{
		Addr:     os.Getenv("REDIS_ADDR"),
		Password: os.Getenv("REDIS_PASSWORD"),
	}
}

func makeValkeyOptions() *valkey.ClientOption {
	return &valkey.ClientOption{
		InitAddress: strings.Split(os.Getenv("VALKEY_ADDR"), ","),
		Password:    os.Getenv("VALKEY_PASSWORD"),
	}
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type redisStore struct {
	cli                  *redis.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func (r *redisStore) sessionKey(sessionID string) string {
	return r.sessionPrefix + sessionID
}

func (r *redisStore) Ping(ctx context.Context) error {
	result, err := r.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	val, err := r.cli.Get(ctx, r.sessionKey(sessionID)).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}
	var info types.SandboxInfo
	if err := json.Unmarshal([]byte(val), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return fmt.Errorf("ExpiresAt is zero")
	}

	key := r.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	pipe := r.cli.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, r.expiryIndexKey, redis.Z{
		Score:  float64(sandboxStore.ExpiresAt.Unix()),
		Member: sandboxStore.SessionID,
	})
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandboxStore.SessionID,
	})
	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	key := r.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}
	result, err := r.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return ErrKeyNotExists
	}
	return nil
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionKey(sessionID)
	pipe := r.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, r.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, r.lastActivityIndexKey, sessionID)
	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	sessionIDs, err := r.cli.ZRangeByScore(ctx, r.expiryIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	sessionIDs, err := r.cli.ZRangeByScore(ctx, r.lastActivityIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return r.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}
	pipe := r.cli.Pipeline()
	cmds := make([]*redis.StringCmd, len(sessionIDs))
	for i, sid := range sessionIDs {
		cmds[i] = pipe.Get(ctx, r.sessionKey(sid))
	}
	_, _ = pipe.Exec(ctx)

	var result []*types.SandboxInfo
	for i, cmd := range cmds {
		val, err := cmd.Result()
		if err == redis.Nil {
			continue
		}
		if err != nil {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &info); err != nil {
			continue
		}
		result = append(result, &info)
		_ = sessionIDs[i]
	}
	return result, nil
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session id is empty")
	}
	if at.IsZero() {
		at = time.Now()
	}
	key := r.sessionKey(sessionID)
	exists, err := r.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}
	return r.cli.ZAdd(ctx, r.lastActivityIndexKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (r *redisStore) Close() error {
	return r.cli.Close()
}

