package router

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"strings"

	"github.com/golang-jwt/jwt/v5"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

const (
	rsaKeySize       = 2048
	jwtExpiration    = 5 * time.Minute
	IdentitySecretName  = "picod-router-identity"
	PrivateKeyDataKey  = "private.pem"
	PublicKeyDataKey   = "public.pem"
)

var IdentityNamespace = os.Getenv("AGENTCUBE_NAMESPACE")
if IdentityNamespace == "" {
	IdentityNamespace = "default"
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() (*JWTManager, error) {
	key, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, err
	}
	return &JWTManager{
		privateKey: key,
		publicKey:  &key.PublicKey,
	}, nil
}

func (m *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now()
	tokenClaims := jwt.MapClaims{
		"exp": now.Add(jwtExpiration).Unix(),
		"iat": now.Unix(),
		"iss": "agentcube-router",
	}
	for k, v := range claims {
		tokenClaims[k] = v
	}
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(m.privateKey)
}

func (m *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	if m.clientset == nil {
		config, err := rest.InClusterConfig()
		if err != nil {
			klog.Warningf("not in cluster, using ephemeral keys: %v", err)
			return nil
		}
		client, err := kubernetes.NewForConfig(config)
		if err != nil {
			return err
		}
		m.clientset = client
	}

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
			Labels: map[string]string{
				"app":      "agentcube",
				"component": "router",
			},
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(m.privateKey),
			}),
			PublicKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "PUBLIC KEY",
				Bytes: x509.MarshalPKIXPublicKey(m.publicKey),
			}),
		},
	}

	created, err := m.clientset.CoreV1().Secrets(IdentityNamespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if apierrors.IsAlreadyExists(err) {
			existing, getErr := m.clientset.CoreV1().Secrets(IdentityNamespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
			if getErr != nil {
				return getErr
			}
			return m.loadPrivateKeyPEM(existing.Data[PrivateKeyDataKey])
		}
		return err
	}
	klog.Infof("created identity secret %s/%s", created.Namespace, created.Name)
	return nil
}

func (m *JWTManager) loadPrivateKeyPEM(data []byte) error {
	block, _ := pem.Decode(data)
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}
	key, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return err
	}
	m.privateKey = key
	m.publicKey = &key.PublicKey
	return nil
}

package router

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"os"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const sessionHeader = "x-agentcube-session-id"

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	transport := &http.Transport{
		MaxIdleConnsPerHost: 100,
		DisableCompression:  false,
	}
	http2.ConfigureTransport(transport)

	client := &http.Client{
		Timeout:   2 * time.Minute,
		Transport: transport,
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      client,
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		info, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return info, nil
		}
		if err != store.ErrNotFound {
			return nil, err
		}
		return nil, api.NewSessionNotFoundError(sessionID)
	}

	createURL := m.workloadMgrAddr + "/v1/agent-runtime"
	if kind == types.CodeInterpreterKind {
		createURL = m.workloadMgrAddr + "/v1/code-interpreter"
	}

	reqBody, _ := json.Marshal(map[string]string{
		"kind":      kind,
		"name":      name,
		"namespace": namespace,
	})

	req, err := http.NewRequestWithContext(ctx, "POST", createURL, strings.NewReader(string(reqBody)))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")

	if token := m.loadWorkloadManagerAuthToken(); token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode == http.StatusNotFound {
		return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
	}
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("workload manager returned %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.Unmarshal(body, &createResp); err != nil {
		return nil, err
	}
	if createResp.SessionID == "" {
		return nil, fmt.Errorf("empty sessionId in create response")
	}

	return &types.SandboxInfo{
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		SessionID:   createResp.SessionID,
		EntryPoints: createResp.EntryPoints,
	}, nil
}

func (m *manager) loadWorkloadManagerAuthToken() string {
	data, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		if !os.IsNotExist(err) {
			klog.Warningf("failed to read service account token: %v", err)
		}
		return ""
	}
	return strings.TrimSpace(string(data))
}

func getEntryPointURL(info *types.SandboxInfo, invocationPath string) (string, error) {
	if len(info.EntryPoints) == 0 {
		return "", fmt.Errorf("no entry point found for sandbox")
	}

	for _, ep := range info.EntryPoints {
		if strings.HasPrefix(invocationPath, ep.Path) {
			return buildEntryURL(ep), nil
		}
	}

	return buildEntryURL(info.EntryPoints[0]), nil
}

func buildEntryURL(ep types.SandboxEntryPoint) string {
	endpoint := ep.Endpoint
	if ep.Protocol != "" && !strings.Contains(endpoint, "://") {
		endpoint = strings.ToLower(ep.Protocol) + "://" + endpoint
	}
	return endpoint
}

package router

import (
	"net/http"
	"net/http/httputil"
	"net/url"

	"github.com/gin-gonic/gin"
)

func (s *Server) forwardToSandbox(c *gin.Context, targetURL string, sessionID string) error {
	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	director := proxy.Director
	proxy.Director = func(req *http.Request) {
		director(req)
		if req.URL.Path != "" && req.URL.Path[0] != '/' {
			req.URL.Path = "/" + req.URL.Path
		}
		req.Host = targetURL.Host
		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		req.Header.Set("X-Forwarded-For", c.ClientIP())

		if sessionID != "" {
			req.Header.Set("Authorization", "Bearer "+sessionID)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set(sessionHeader, sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
			return
		}
		if strings.Contains(errMsg, "timeout") {
			http.Error(w, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
			return
		}
		http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
	}

	proxy.ServeHTTP(w, r)
	return nil
}

func parseTargetURL(entryPoint string) (*url.URL, error) {
	if !strings.Contains(entryPoint, "://") {
		entryPoint = "http://" + entryPoint
	}
	return url.Parse(entryPoint)
}

