func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error": "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	s.handleInvoke(c, "AgentRuntime")
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	s.handleInvoke(c, "CodeInterpreter")
}

func (s *Server) handleInvoke(c *gin.Context, kind string) {
	ctx := c.Request.Context()
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader(sessionHeader)

	_ = s.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now())

	info, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, kind)
	if err != nil {
		handleGetSandboxError(c, err)
		return
	}

	_ = s.storeClient.UpdateSessionLastActivity(ctx, info.SessionID, time.Now())

	upstream, err := getEntryPointURL(info, "/"+path)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	var jwtToken string
	if kind == "Sandbox" || kind == "SandboxClaim" {
		jwtToken, err = s.jwtManager.GenerateToken(map[string]interface{}{
			"session_id": info.SessionID,
		})
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{
				"code":  "JWT_SIGNING_FAILED",
				"error": "failed to sign request",
			})
			return
		}
	}

	targetURL, err := parseTargetURL(upstream)
	if err != nil {
		c.JSON(http.StatusBadGateway, gin.H{"error": "invalid upstream URL"})
		return
	}

	s.forwardToSandboxWithJWT(c, targetURL, info.SessionID, jwtToken)
}

func (s *Server) forwardToSandboxWithJWT(c *gin.Context, targetURL *url.URL, sessionID string, jwtToken string) {
	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	director := proxy.Director
	proxy.Director = func(req *http.Request) {
		director(req)
		path := req.URL.Path
		if path != "" && path[0] != '/' {
			req.URL.Path = "/" + path
		}
		req.Host = targetURL.Host
		req.Header.Set("X-Forwarded-Host", req.Host)
		if req.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		req.Header.Set("X-Forwarded-For", c.ClientIP())
		if jwtToken != "" {
			req.Header.Set("Authorization", "Bearer "+jwtToken)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set(sessionHeader, sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
			return
		}
		if strings.Contains(errMsg, "timeout") {
			http.Error(w, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
			return
		}
		http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func handleGetSandboxError(c *gin.Context, err error) {
	if apiStatus, ok := err.(interface{ APIStatus() interface{} }); ok && apiStatus.APIStatus() != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

package router

import (
	"sync"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/client-go/kubernetes"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager SessionManager
	storeClient    store.Store
	httpTransport  *http.Transport
	jwtManager     *JWTManager
	sem            chan struct{}
}

func NewServer(config *Config, storeClient store.Store) (*Server, error) {
	if config.Port == "" {
		config.Port = "8080"
	}
	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = 1000
	}

	if config.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	jwtMgr, err := NewJWTManager()
	if err != nil {
		return nil, err
	}

	sessionMgr, err := NewSessionManager(storeClient)
	if err != nil {
		return nil, err
	}

	srv := &Server{
		config:         config,
		engine:         engine,
		sessionManager: sessionMgr,
		storeClient:    storeClient,
		httpTransport: &http.Transport{
			IdleConnTimeout:  0,
			DisableCompression: false,
		},
		jwtManager: jwtMgr,
		sem:        make(chan struct{}, config.MaxConcurrentRequests),
	}

	srv.registerRoutes()
	return srv, nil
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1")
	v1.Use(gin.Logger(), gin.Recovery(), s.concurrencyLimitMiddleware())
	{
		v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	}
}

func (s *Server) concurrencyLimitMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case s.sem <- struct{}{}:
			defer func() { <-s.sem }()
			c.Next()
		default:
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
		}
	}
}

func (s *Server) Start(ctx context.Context) error {
	addr := s.config.Port
	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return fmt.Errorf("TLS enabled but cert/key not provided")
		}
		s.httpServer = &http.Server{
			Addr:         ":" + addr,
			Handler:     s.engine,
			ReadTimeout:  30 * time.Second,
			IdleTimeout:  90 * time.Second,
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	s.httpServer = &http.Server{
		Addr:         ":" + addr,
		Handler:     h2c.NewHandler(s.engine, &http2.Server{}),
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		shutdownCtx, cancel := context.WithTimeout(ctx, 10*time.Second)
		defer cancel()
		return s.httpServer.Shutdown(shutdownCtx)
	}
	return nil
}

package router

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	rsaKeySize          = 2048
	jwtExpiration       = 5 * time.Minute
	IdentitySecretName  = "picod-router-identity"
	PrivateKeyDataKey   = "private.pem"
	PublicKeyDataKey    = "public.pem"
)

var IdentityNamespace = getEnvOrDefault("AGENTCUBE_NAMESPACE", "default")

func getEnvOrDefault(key, defaultVal string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return defaultVal
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() (*JWTManager, error) {
	key, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, err
	}
	return &JWTManager{
		privateKey: key,
		publicKey:  &key.PublicKey,
	}, nil
}

func (m *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now()
	tokenClaims := jwt.MapClaims{
		"exp": now.Add(jwtExpiration).Unix(),
		"iat": now.Unix(),
		"iss": "agentcube-router",
	}
	for k, v := range claims {
		tokenClaims[k] = v
	}
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(m.privateKey)
}

func (m *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	if m.clientset == nil {
		config, err := rest.InClusterConfig()
		if err != nil {
			klog.Warningf("not in cluster, using ephemeral keys: %v", err)
			return nil
		}
		client, err := kubernetes.NewForConfig(config)
		if err != nil {
			return err
		}
		m.clientset = client
	}

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
			Labels: map[string]string{
				"app":       "agentcube",
				"component": "router",
			},
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "RSA PRIVATE KEY",
				Bytes: x509.MarshalPKCS1PrivateKey(m.privateKey),
			}),
			PublicKeyDataKey: pem.EncodeToMemory(&pem.Block{
				Type:  "PUBLIC KEY",
				Bytes: x509.MarshalPKIXPublicKey(m.publicKey),
			}),
		},
	}

	created, err := m.clientset.CoreV1().Secrets(IdentityNamespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if errors.IsAlreadyExists(err) {
			existing, getErr := m.clientset.CoreV1().Secrets(IdentityNamespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
			if getErr != nil {
				return getErr
			}
			return m.loadPrivateKeyPEM(existing.Data[PrivateKeyDataKey])
		}
		return err
	}
	klog.Infof("created identity secret %s/%s", created.Namespace, created.Name)
	return nil
}

func (m *JWTManager) loadPrivateKeyPEM(data []byte) error {
	block, _ := pem.Decode(data)
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}
	key, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return err
	}
	m.privateKey = key
	m.publicKey = &key.PublicKey
	return nil
}

func (m *JWTManager) GetPublicKey() *rsa.PublicKey {
	return m.publicKey
}

package router

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const sessionHeader = "x-agentcube-session-id"

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	transport := &http.Transport{
		MaxIdleConnsPerHost: 100,
		DisableCompression:  false,
	}

	client := &http.Client{
		Timeout:   2 * time.Minute,
		Transport: transport,
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      client,
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		info, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return info, nil
		}
		if err != store.ErrNotFound {
			return nil, err
		}
		return nil, api.NewSessionNotFoundError(sessionID)
	}

	createURL := m.workloadMgrAddr + "/v1/agent-runtime"
	if kind == types.CodeInterpreterKind {
		createURL = m.workloadMgrAddr + "/v1/code-interpreter"
	}

	reqBody, _ := json.Marshal(map[string]string{
		"kind":      kind,
		"name":      name,
		"namespace": namespace,
	})

	req, err := http.NewRequestWithContext(ctx, "POST", createURL, strings.NewReader(string(reqBody)))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")

	if token := m.loadWorkloadManagerAuthToken(); token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode == http.StatusNotFound {
		return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
	}
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("workload manager returned %d: %s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.Unmarshal(body, &createResp); err != nil {
		return nil, err
	}
	if createResp.SessionID == "" {
		return nil, fmt.Errorf("empty sessionId in create response")
	}

	return &types.SandboxInfo{
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		SessionID:   createResp.SessionID,
		EntryPoints: createResp.EntryPoints,
	}, nil
}

func (m *manager) loadWorkloadManagerAuthToken() string {
	data, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		if !os.IsNotExist(err) {
			klog.Warningf("failed to read service account token: %v", err)
		}
		return ""
	}
	return strings.TrimSpace(string(data))
}

func getEntryPointURL(info *types.SandboxInfo, invocationPath string) (string, error) {
	if len(info.EntryPoints) == 0 {
		return "", fmt.Errorf("no entry point found for sandbox")
	}

	for _, ep := range info.EntryPoints {
		if strings.HasPrefix(invocationPath, ep.Path) {
			return buildEntryURL(ep), nil
		}
	}

	return buildEntryURL(info.EntryPoints[0]), nil
}

func buildEntryURL(ep types.SandboxEntryPoint) string {
	endpoint := ep.Endpoint
	if ep.Protocol != "" && !strings.Contains(endpoint, "://") {
		endpoint = strings.ToLower(ep.Protocol) + "://" + endpoint
	}
	return endpoint
}

