		http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func parseTargetURL(entryPoint string) (string, error) {
	if !strings.Contains(entryPoint, "://") {
		entryPoint = "http://" + entryPoint
	}
	_, err := url.Parse(entryPoint)
	if err != nil {
		return "", err
	}
	return entryPoint, nil
}

func handleGetSandboxError(c *gin.Context, err error) {
	if apiErr, ok := err.(interface{ StatusCode() int }); ok && apiErr.StatusCode() != 0 {
		code := apiErr.StatusCode()
		msg := err.Error()
		if code == http.StatusInternalServerError {
			msg = "internal server error"
		}
		c.JSON(code, gin.H{"error": msg})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

