package router

import (
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"

	"github.com/gin-gonic/gin"
)

func (s *Server) forwardToSandbox(c *gin.Context, targetURL string, sessionID string, jwtToken string) {
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		c.JSON(http.StatusBadGateway, gin.H{"error": "invalid upstream URL"})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(parsedURL)
	proxy.Transport = s.httpTransport

	director := proxy.Director
	proxy.Director = func(req *http.Request) {
		director(req)
		path := req.URL.Path
		if path != "" && path[0] != '/' {
			req.URL.Path = "/" + path
		}
		req.Host = parsedURL.Host
		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		req.Header.Set("X-Forwarded-For", c.ClientIP())
		if jwtToken != "" {
			req.Header.Set("Authorization", "Bearer "+jwtToken)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set(sessionHeader, sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
			return
		}
		if strings.Contains(errMsg, "timeout") {
			http.Error(w, `{"error":"sandbox timeout"}`, http.StatusGatewayTimeout)
			return
		}
		http.Error(w, `{"error":"sandbox unreachable"}`, http.StatusBadGateway)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func parseTargetURL(entryPoint string) (string, error) {
	if !strings.Contains(entryPoint, "://") {
		entryPoint = "http://" + entryPoint
	}
	_, err := url.Parse(entryPoint)
	if err != nil {
		return "", err
	}
	return entryPoint, nil
}

func handleGetSandboxError(c *gin.Context, err error) {
	if apiErr, ok := err.(interface{ StatusCode() int }); ok && apiErr.StatusCode() != 0 {
		code := apiErr.StatusCode()
		msg := err.Error()
		if code == http.StatusInternalServerError {
			msg = "internal server error"
		}
		c.JSON(code, gin.H{"error": msg})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}
